import{c as t,Q as a,j as r,m as o}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"guide/admin/changelog.md","filePath":"guide/admin/changelog.md","lastUpdated":1778862269000}'),i={name:"guide/admin/changelog.md"};function l(n,e,s,h,d,g){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>The <strong>Changelog</strong> page is the operator-facing view of the same content customers see in their Customer Portal under <strong>What&#39;s New</strong>. It is a chronological, public-facing record of completed releases and their notes.</p><h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><ul><li>Header with title and description.</li><li>Filter toolbar — search, type filter, month filter, <strong>Clear</strong>.</li><li>A row of month links (&quot;Jump to&quot;) above the cards.</li><li>Cards grouped by month, newest first.</li><li><strong>Load More</strong> at the bottom.</li></ul><h2 id="filters" tabindex="-1">Filters <a class="header-anchor" href="#filters" aria-label="Permalink to &quot;Filters&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Filter</th><th>Behaviour</th></tr></thead><tbody><tr><td><strong>Search</strong></td><td>Substring match on version number.</td></tr><tr><td><strong>Type</strong></td><td>Feature / Hotfix / Config, multi-select.</td></tr><tr><td><strong>Month</strong></td><td>Reverse-chronological list of months that have releases.</td></tr><tr><td><strong>Clear</strong></td><td>Resets everything.</td></tr><tr><td>Count</td><td>&quot;5 of 47&quot; — filtered entries vs. total.</td></tr></tbody></table><h2 id="changelog-card" tabindex="-1">Changelog card <a class="header-anchor" href="#changelog-card" aria-label="Permalink to &quot;Changelog card&quot;">​</a></h2><p>Each card represents one completed release:</p><ul><li>Release name or version (monospace, bold).</li><li>Type badge (Feature / Hotfix / Config).</li><li>Completion date.</li><li>Release notes rendered as rich HTML (headings, bold, lists, images).</li><li><strong>View release →</strong> link to the release detail page.</li></ul><h2 id="what-appears-here" tabindex="-1">What appears here <a class="header-anchor" href="#what-appears-here" aria-label="Permalink to &quot;What appears here&quot;">​</a></h2><ul><li>Only releases in the <code>completed</code> status.</li><li>Only releases that have release notes. Config releases that were submitted without notes do not appear, even if they completed successfully.</li></ul><h2 id="pagination" tabindex="-1">Pagination <a class="header-anchor" href="#pagination" aria-label="Permalink to &quot;Pagination&quot;">​</a></h2><p>Releases load in pages of 5. Click <strong>Load More</strong> to fetch the next page. Loaded pages stay in memory — switching filters re-applies them to what is loaded.</p><h2 id="tips-for-writing-release-notes" tabindex="-1">Tips for writing release notes <a class="header-anchor" href="#tips-for-writing-release-notes" aria-label="Permalink to &quot;Tips for writing release notes&quot;">​</a></h2><p>The notes here are what your customers see, so write them for customers, not for engineers.</p><ul><li>Lead with the user-visible change, not the implementation.</li><li>Group by area (Tenants, Billing, Migrations …) when a release touches several.</li><li>Show screenshots of the new UI when it helps.</li><li>For hotfixes, say what was broken in plain language.</li><li>Don&#39;t dump JIRA tickets.</li></ul><p>The rich-text editor on the <a href="./releases#creating-a-new-release">New Release</a> page supports images — paste them inline rather than linking to an external URL.</p>',17)])])}const u=t(i,[["render",l]]);export{p as __pageData,u as default};
